insert into blocks (site_slug, section, kind, position, data) values ('antyodaya', 'lamp', 'lines', 0, '{"idle":"a diya on a government notice board. someone lit it for the number.","watched":"it steadies when watched. most things do."}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('antyodaya', 'excerpt', 'prose', 0, '{"text":"The notice board had outlived four governments and one coat of paint. Tonight it carried a single sheet, and the sheet carried a number, and the number was the count of grain sacks that had actually arrived — not the count that had been signed for. Between those two figures lived everything Kabir intended to burn down. Someone had set a diya on the ledge beneath it, the way you light a lamp for a god or for a body. He stood in the queue''s leftover silence and understood, with the cold precision of a man reading his own blood report, that the lamp was for neither. It was for the number. The village had begun to worship the truth — carefully, the way you worship anything that can still be taken away.","src":"— FROM THE PROLOGUE · KARAHIYA DISTRICT · YEAR ONE"}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('antyodaya', 'dossiers', 'heading', 0, '{"eyebrow":"the x-ray","h2":"Dossiers unlock <em>as you earn them.</em>","sub":"Every reader gets the story. Readers who go deep get the files under the story — timelines, ledgers, the things characters know about each other and shouldn''t. Tiers open with reading progress. The novel keeps score; of course it does."}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('antyodaya', 'how', 'cards', 0, '{"cards":[{"k":"TWO LIGHTS","html":"<b>Dark</b> for night reading, <b>paper</b> for daylight. The prose doesn''t change. Your conscience might."},{"k":"SEVEN MACHINES","html":"Small interactive scenes live inside the chapters — a rupee you can follow, a letter you can almost send. <b>The prose watches back.</b>"},{"k":"THE GATE","html":"We ask for your email after chapter three. <b>By then you''ll know if we''ve earned it.</b> Until then, read free, owe nothing."}]}'::jsonb);
