insert into blocks (site_slug, section, kind, position, data) values ('arcade', 'lede', 'lede', 2, '{"html":"Five machines, five interaction grammars, zero loot boxes. Each one makes a claim about how your life actually works — then hands you the controls and lets you <b>lose to your own habits</b> in a safe, well-lit room. Cheaper than the real-world version. Significantly faster feedback."}'::jsonb);
