insert into blocks (site_slug, section, kind, position, data) values ('arcade', 'capture', 'kv', 5, '{"k":"ONE NEW MACHINE A MONTH.","sub":"No essays, just the cartridge.","placeholder":"your@address","button":"SUBSCRIBE","ok":"Noted. One cartridge a month.","err":"Didn''t take. Try again."}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('arcade', 'studio', 'kv', 6, '{"k":"COMMISSION A MACHINE","body":"I build the playable version of your course/book''s core idea. White-label, your domain, two-week turnaround.","cta":{"label":"operator.zephyrcode.live/commission →","href":"https://operator.zephyrcode.live/commission"}}'::jsonb);
insert into sims (slug, name, grammar, blurb, position) values ('leap', 'THE LEAP', 'GRAMMAR · DRAG THE FUTURE', 'Drag the month you quit your job. Watch the valley floor rise — or not — to meet you.', 1);
insert into sims (slug, name, grammar, blurb, position) values ('bedtime', 'BEDTIME', 'GRAMMAR · SWIPE & SUFFER', 'A dilemma deck with four meters that remember exactly what you chose at 9:47pm.', 2);
insert into sims (slug, name, grammar, blurb, position) values ('plate', 'THE PLATE', 'GRAMMAR · DIRECT MANIPULATION', 'Build the meal with your hands; the glucose curve answers in real time. The curve is honest. Brutally.', 3);
insert into sims (slug, name, grammar, blurb, position) values ('cascade', 'CASCADE', 'GRAMMAR · AGENTS, RELEASED', 'How ideas actually spread — simple contagion versus the complex kind that needs three friends and a nudge.', 4);
insert into sims (slug, name, grammar, blurb, position) values ('tax', 'THE INTERRUPTION TAX', 'GRAMMAR · THE LEDGER', 'What one "quick meeting" really costs a maker''s afternoon. Bring a strong stomach.', 5);
insert into sites (slug, host, title, description, accent, og_image, nav_order) values ('read', 'read.zephyrcode.live', 'READ — the shelf with a temperature · ZephyrCode', 'Fourteen books on a single heat gradient — from Dinkar''s war drums to the dissolving quiet of The Book of Mirdad. Pick by the day you''re having, not the canon you''re told.', '#E85D2A', null, 6) on conflict (slug) do update set host=excluded.host, title=excluded.title, description=excluded.description, accent=excluded.accent, og_image=excluded.og_image, nav_order=excluded.nav_order;
insert into blocks (site_slug, section, kind, position, data) values ('read', 'top', 'crumb', 1, '{"text":"READ · FIRE → STILLNESS"}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('read', 'hero', 'heading', 2, '{"eyebrow":"read.zephyrcode.live","h1Html":"The shelf with <em>a temperature.</em>","ledeHtml":"Fourteen books on one axis — <b>fire to stillness</b>, Dinkar''s war drums to the dissolving quiet of Mirdad. Genre is a librarian''s problem. The only real question is what the day is asking for. Set the dial; the shelf answers."}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('read', 'dial', 'dial', 3, '{"fire":"FIRE — pre-training, pre-war, pre-deadline","still":"STILL — after, and above","ariaLabel":"Mood: fire to stillness","askLines":[[0,"the day wants drums. the shelf agrees."],[25,"voltage with a spine. musashi is watching your posture."],[45,"the bridge: burn, but without smoke."],[65,"the emperor and the poet pour you something."],[82,"breathe out. the arguments are dissolving."],[101,""]]}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('read', 'start', 'picks', 4, '{"k":"START THIS WEEK · THE FOUR-BOOK IGNITION","picks":[["Rashmirathi","THE CENTER OF GRAVITY"],["The Book of Five Rings","THE TRAINING PARTNER"],["Bhagavad Gita","THE HINGE"],["Siddhartha","THE EXHALE"]],"tail":"Read the fire standing up and the stillness sitting down. There is no third posture; that''s the whole curriculum."}'::jsonb);
insert into books (position, title, author, pos, register, lang, note) values (1, 'Haldighati', 'Shyam Narayan Pandey', 0.02, 'FIRE', 'HINDI', 'Hooves, steel, and a horse that out-acts most protagonists. Pure veer rasa, zero apologies.');
insert into books (position, title, author, pos, register, lang, note) values (2, 'Rashmirathi', 'Ramdhari Singh Dinkar', 0.07, 'FIRE', 'HINDI', 'Karna''s answer to the accident of birth, delivered at sword-length. Krishna''s warning canto alone is worth the shelf. Start here.');
insert into books (position, title, author, pos, register, lang, note) values (3, 'Parashuram ki Prateeksha', 'Dinkar', 0.12, 'FIRE', 'HINDI', 'A nation scolded awake after 1962. Reads like a slap that loves you.');
insert into books (position, title, author, pos, register, lang, note) values (4, 'Ram ki Shakti Puja', 'Suryakant Tripathi ''Nirala''', 0.18, 'FIRE', 'HINDI', 'Even gods rehearse. Ram confronting his own weakness on the eve of war — dense, towering, worth the climb.');
insert into books (position, title, author, pos, register, lang, note) values (5, 'Hunkar', 'Dinkar', 0.22, 'FIRE', 'HINDI', 'The warm-up drum. Short blasts of voltage for mornings that start heavy.');
insert into books (position, title, author, pos, register, lang, note) values (6, 'The Book of Five Rings', 'Musashi · tr. Cleary', 0.28, 'FIRE', 'EN', 'Sixty duels undefeated, and his deepest advice is about attention. Talks straight to the gloves. Reread yearly.');
insert into books (position, title, author, pos, register, lang, note) values (7, 'Thus Spoke Zarathustra', 'Friedrich Nietzsche', 0.34, 'FIRE', 'EN · HARD', 'Osho''s number one. Prose-poetry that bites if grabbed — read in passages, like lifting, never to failure.');
insert into books (position, title, author, pos, register, lang, note) values (8, 'Kurukshetra', 'Dinkar', 0.45, 'BRIDGE', 'HINDI', 'Violence cross-examined on a bed of arrows. Where the fire poems start asking questions.');
insert into books (position, title, author, pos, register, lang, note) values (9, 'Bhagavad Gita', 'tr. Eknath Easwaran', 0.52, 'BRIDGE', 'EN', 'A warrior talked back into the fight and taught to burn without smoke. If you read one book off this shelf, this.');
insert into books (position, title, author, pos, register, lang, note) values (10, 'Meditations', 'Marcus Aurelius', 0.62, 'BRIDGE', 'EN', 'An emperor''s private notes on not becoming the thing he ruled. Written for an audience of one; somehow about you.');
insert into books (position, title, author, pos, register, lang, note) values (11, 'Madhushala', 'Harivansh Rai Bachchan', 0.68, 'BRIDGE', 'HINDI', 'Intoxication as theology. Sip, don''t gulp — every quatrain is a full pour.');
insert into books (position, title, author, pos, register, lang, note) values (12, 'Siddhartha', 'Hermann Hesse', 0.78, 'STILL', 'EN · EASY', 'Enlightenment by way of everything the monks renounce. The warm door into the quiet wing.');
insert into books (position, title, author, pos, register, lang, note) values (13, 'Enlightenment: The Only Revolution', 'Osho on Ashtavakra', 0.86, 'STILL', 'EN', 'The hammer that whispers: you are already free — stop applying. One discourse at a time, preferably horizontal.');
insert into books (position, title, author, pos, register, lang, note) values (14, 'The Book of Mirdad', 'Mikhail Naimy', 0.95, 'STILL', 'EN · SHORT', 'The quiet book that ends arguments by dissolving the arguer. Why Osho is Osho.');
insert into sites (slug, host, title, description, accent, og_image, nav_order) values ('watch', 'watch.zephyrcode.live', 'WATCH — eight mood channels · ZephyrCode', 'Series and films sorted by state of mind, not genre — from Brain on Fire to Decompress. Scored against one viewer''s taste profile, ranked without mercy.', '#C9A45C', null, 7) on conflict (slug) do update set host=excluded.host, title=excluded.title, description=excluded.description, accent=excluded.accent, og_image=excluded.og_image, nav_order=excluded.nav_order;
insert into blocks (site_slug, section, kind, position, data) values ('watch', 'hero', 'hero', 1, '{"eyebrow":"watch.zephyrcode.live","h1":"Eight channels. <em>Zero browsing.</em>","lede":"Streaming menus answer \"what exists.\" This answers <b>\"what is tonight for?\"</b> Every title is scored against one viewer''s taste profile — cerebral mystery, hard SF with a pulse, crime with a conscience — and ranked without mercy. <b>Dark</b> is the north star. It was always going to be."}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('watch', 'np', 'kv', 2, '{"tunedPrefix":"NOW TUNED · CH","footnote":"MATCH % = FIT TO THE HOUSE TASTE PROFILE, NOT QUALITY. QUALITY IS ASSUMED; WE DON''T SHELVE FILLER.","aria":"Mood channels"}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('watch', 'crumb', 'label', 3, '{"text":"WATCH · EIGHT MOOD CHANNELS"}'::jsonb);
insert into watch_titles (channel_id, title, match, platform, why, position) select ch.id, t.* from ch, (values ('Dark', 99::int, 'NETFLIX', 'Three generations, one cave, zero wasted scenes. The reference standard — watched five times in this house, still undefeated.', 1::int), ('Bodies', 94::int, 'NETFLIX', 'One corpse, four detectives, four timelines. A loop that actually closes.', 2::int), ('3 Body Problem', 92::int, 'NETFLIX', 'Physics breaks first; people follow. Read the trilogy and feel superior, gently.', 3::int)) as t(title, match, platform, why, position);
insert into watch_titles (channel_id, title, match, platform, why, position) select ch.id, t.* from ch, (values ('Dept. Q', 93::int, 'NETFLIX', 'Cold cases, colder detective. Procedural craft with actual procedure.', 1::int), ('Dark Matter', 90::int, 'ATV+', 'One choice, infinite Jasons. Crouch''s box, opened properly.', 2::int), ('Sherlock', 87::int, 'NETFLIX', 'The deduction-as-spectacle blueprint. Seasons one and two, then leave the table.', 3::int)) as t(title, match, platform, why, position);
insert into watch_titles (channel_id, title, match, platform, why, position) select ch.id, t.* from ch, (values ('My Name', 91::int, 'NETFLIX', 'Revenge with footwork. The fight choreography respects your training eye.', 1::int), ('The Night Comes for Us', 88::int, 'NETFLIX', 'Indonesian action at maximum honesty. Stretch first.', 2::int), ('Extraction', 84::int, 'NETFLIX', 'One-take logistics. Cardio for the camera operator.', 3::int)) as t(title, match, platform, why, position);
insert into watch_titles (channel_id, title, match, platform, why, position) select ch.id, t.* from ch, (values ('The Family Man', 95::int, 'PRIME', 'Middle management versus national security. The most honest job description on television.', 1::int), ('Slow Horses', 93::int, 'ATV+', 'Failed spies, magnificent spite. Lamb is a one-man counterargument to LinkedIn.', 2::int), ('The Night Manager', 87::int, 'JIO', 'Le Carré with better hotels. Treachery, beautifully lit.', 3::int)) as t(title, match, platform, why, position);
insert into watch_titles (channel_id, title, match, platform, why, position) select ch.id, t.* from ch, (values ('Scam 1992', 94::int, 'SONY', 'A market, a man, a margin call on an entire system. Rewatch material for systems thinkers.', 1::int), ('The Diplomat', 88::int, 'NETFLIX', 'Crisis management as bloodsport. Dialogue with elbows.', 2::int), ('House of Cards', 85::int, 'NETFLIX', 'The machinery of ambition, fourth wall optional. Early seasons, then exit clean.', 3::int)) as t(title, match, platform, why, position);
insert into watch_titles (channel_id, title, match, platform, why, position) select ch.id, t.* from ch, (values ('Severance', 96::int, 'ATV+', 'Work-life balance, surgically enforced. The most elegant horror premise of the decade.', 1::int), ('Mr. Robot', 93::int, 'PRIME', 'An unreliable narrator with root access. Society gets debugged; so does he.', 2::int), ('The OA', 90::int, 'NETFLIX', 'Faith, movement, and a swing for the fences that connects. Yes, even the ending.', 3::int)) as t(title, match, platform, why, position);
insert into watch_titles (channel_id, title, match, platform, why, position) select ch.id, t.* from ch, (values ('Shōgun', 96::int, 'JIO', 'Power as language lesson. Every silence is load-bearing.', 1::int), ('Pachinko', 95::int, 'ATV+', 'Four generations carried across water. Television that earns the word literature.', 2::int), ('The Queen''s Gambit', 91::int, 'NETFLIX', 'Genius as addiction with better lighting. The ceiling scene alone.', 3::int)) as t(title, match, platform, why, position);
insert into watch_titles (channel_id, title, match, platform, why, position) select ch.id, t.* from ch, (values ('Our Planet', 86::int, 'NETFLIX', 'Attenborough administers perspective. The only feed worth doomscrolling.', 1::int), ('Chef''s Table', 84::int, 'NETFLIX', 'Obsession, plated. Watch a master descend, compress, animate, ship — sound familiar?', 2::int), ('Ted Lasso', 88::int, 'ATV+', 'Sincerity played as a power move. Recovery content for cynics.', 3::int)) as t(title, match, platform, why, position);
insert into sites (slug, host, title, description, accent, og_image, nav_order) values ('listen', 'listen.zephyrcode.live', 'LISTEN — the listening room · ZephyrCode', 'Five things a rig must prove — weight, stage, breath, detail, dynamics — and the tracks that interrogate each one. Reference chain: HD 660S2 into a FiiO K11 R2R, balanced, high gain.', '#E85D2A', null, 8) on conflict (slug) do update set host=excluded.host, title=excluded.title, description=excluded.description, accent=excluded.accent, og_image=excluded.og_image, nav_order=excluded.nav_order;
insert into blocks (site_slug, section, kind, position, data) values ('listen', 'hero', 'hero', 1, '{"eyebrow":"listen.zephyrcode.live","h1":"Five things a rig <em>must prove.</em>","lede":"Specifications are testimony; <b>music is cross-examination.</b> Below: the five proofs every chain in this house has to pass, the tracks that interrogate each one, and the scope showing what you should be hearing. No burn-in ritual required — <b>your ears do the burning-in.</b>"}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('listen', 'scope', 'kv', 2, '{"labPrefix":"PROOF ","hzLine":"REFERENCE TRACE · NOT TO SCALE · OBVIOUSLY","aria":"The five proofs"}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('listen', 'ignition', 'kv', 3, '{"k":"BONUS PROOF · IGNITION","t":"DIVINE · Seedhe Maut · gym volume","s":"THE IEM DEPARTMENT (ZERO:RED) HANDLES GLOVES-ON HOURS. THE HEADPHONES STAY HOME AND JUDGE."}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('listen', 'rig', 'kv', 4, '{"k":"THE RIG OF RECORD","chain":["SOURCE · LOSSLESS","FiiO K11 R2R","4.4mm BALANCED","SENNHEISER HD 660S2","STERNUM"],"note":"High gain, volume at \"respectful.\" R2R because numbers should pass through a ladder of actual resistors before becoming feelings. The truth-teller screen reads 44.1 when the stream behaves, and you check it the way other people check the weather. <b>Mobile detachment:</b> ZERO:RED IEMs off a ddHiFi dongle — the away kit for a rig that took the home game seriously."}'::jsonb);
insert into blocks (site_slug, section, kind, position, data) values ('listen', 'crumb', 'label', 5, '{"text":"LISTEN · THE LISTENING ROOM"}'::jsonb);
insert into listen_tracks (proof_id, title, artist, why, position) select pf.id, t.* from pf, (values ('Why So Serious?', 'Hans Zimmer', 'The famous low-end descent — a structural inspection for your floor, your seal, your resolve.', 1::int), ('Angel', 'Massive Attack', 'A bassline with a predator''s patience. Texture down where most rigs only rumble.', 2::int)) as t(title, artist, why, position);
insert into listen_tracks (proof_id, title, artist, why, position) select pf.id, t.* from pf, (values ('Bubbles', 'Yosi Horikawa', 'Field recordings that place each droplet at an address. Imaging''s party trick, performed straight-faced.', 1::int), ('Time', 'Hans Zimmer', 'One phrase, twelve entrances. Count the layers arriving; lose count on purpose.', 2::int)) as t(title, artist, why, position);
insert into listen_tracks (proof_id, title, artist, why, position) select pf.id, t.* from pf, (values ('Apocalypse', 'Cigarettes After Sex', 'Reverb tails you could sleep in. The vocal sits close enough to be a confession.', 1::int), ('Riverside', 'Agnes Obel', 'Felt on hammers, floorboards under pedals. You can hear the room thinking.', 2::int)) as t(title, artist, why, position);
insert into listen_tracks (proof_id, title, artist, why, position) select pf.id, t.* from pf, (values ('Hand Covers Bruise', 'Trent Reznor & Atticus Ross', 'A piano decaying over a noise floor that slowly tells the truth about your DAC.', 1::int), ('Says', 'Nils Frahm', 'One arpeggio, ten patient minutes, the swell of the decade. Detail becomes weather.', 2::int)) as t(title, artist, why, position);
insert into listen_tracks (proof_id, title, artist, why, position) select pf.id, t.* from pf, (values ('No Time for Caution', 'Hans Zimmer', 'The docking scene. Organ at full sail. The dynamic swing other tracks gossip about.', 1::int), ('Mars, the Bringer of War', 'Gustav Holst', 'The orchestra as a weapons system — col legno strings like knuckles on wood.', 2::int)) as t(title, artist, why, position);
